def calculate_check_digit(id_number):
    weight_factors = [7, 9, 10, 5, 8, 4, 2, 1, 6, 3, 7, 9, 10, 5, 8, 4, 2]
    check_factors = ['1', '0', 'X', '9', '8', '7', '6', '5', '4', '3', ' 2']
    sum_value = 0
    for i in range(len(id_number)):
        sum_value += int(id_number[i]) * weight_factors[i]
    remainder = sum_value % 11
    return check_factors[remainder]

def get_gender(id_number):
    gender_digit = int(id_number[-2])
    if gender_digit % 2 == 0:
        return 'Female'
    else:
        return 'Male'

def validate_birthday(id_number):
    birthday = id_number[6:14]
    year = int(birthday[0:4])
    month = int(birthday[4:6])
    day = int(birthday[6:8])
    if month < 1 or month > 12:
        return False
    if day < 1 or day > 31:
        return False
    if month in [4, 6, 9, 11] and day > 30:
        return False
    if month == 2:
        if year % 4 == 0 and (year % 100 != 0 or year % 400 == 0):
            if day > 29:
                return False
        elif day > 28:
            return False
    return True

def main():
    id_number = input("请输入身份证号码：")
    if len(id_number) == 15:
        id_number = id_number[0:6] + '19' + id_number[6:]
        id_number += calculate_check_digit(id_number)
    if len(id_number) != 18:
        print("无效的身份证号码")
        return
    check_digit = id_number[-1]
    check_result = calculate_check_digit(id_number[:-1])
    if check_digit != check_result:
        print("无效的身份证号码")
        return
    print("校验通过")
    print("性别：", get_gender(id_number))
    if not validate_birthday(id_number):
        print("生日无效")
    else:
        print("生日合法")

if __name__ == "__main__":
    main()
